python3 << 'PYEOF'
import json, os, glob

sessions_dir = "/root/.openclaw/agents/main/sessions"
# Only main session files (not trajectory, not checkpoint, not sessions.json)
files = sorted(glob.glob(os.path.join(sessions_dir, "*.jsonl")))
files = [f for f in files if "trajectory" not in f and "checkpoint" not in f and "sessions.json" not in f]

for f in files:
    basename = os.path.basename(f)
    user_msgs = []
    assistant_msgs = []
    for line in open(f):
        line = line.strip()
        if not line: continue
        try:
            obj = json.loads(line)
            role = obj.get("role","")
            content = obj.get("content","")
            if role == "user":
                if isinstance(content, list):
                    text = " ".join(c.get("text","") for c in content if isinstance(c,dict) and c.get("type")=="text")
                else:
                    text = str(content)
                text = text.strip()[:500]
                if text and len(text) > 2:
                    user_msgs.append(text)
            elif role == "assistant":
                if isinstance(content, list):
                    text = " ".join(c.get("text","") for c in content if isinstance(c,dict) and c.get("type")=="text")
                else:
                    text = str(content)
                text = text.strip()[:300]
                if text and len(text) > 2:
                    assistant_msgs.append(text)
        except:
            pass
    if user_msgs or assistant_msgs:
        mtime = os.path.getmtime(f)
        from datetime import datetime
        dt = datetime.fromtimestamp(mtime).strftime("%m-%d %H:%M")
        print(f"\n{'='*60}")
        print(f"📅 {dt} | {basename}")
        print(f"   用户消息: {len(user_msgs)}条 | 助手消息: {len(assistant_msgs)}条")
        for i, m in enumerate(user_msgs[:5]):
            print(f"   👤 {m[:200]}")
        if len(user_msgs) > 5:
            print(f"   ... 还有{len(user_msgs)-5}条")
