def redact(d, depth=0):
    if isinstance(d, dict):
        result = {}
        for k, v in d.items():
            if any(s in k.lower() for s in ['token','secret','password','key','credential']):
                result[k] = '[REDACTED]'
            elif depth < 3:
                result[k] = redact(v, depth+1)
            else:
                result[k] = str(v)[:200]
        return result
    elif isinstance(d, list):
