import json, glob, os, re

sessions_dir = "/root/.openclaw/agents/main/sessions"
files = sorted(glob.glob(os.path.join(sessions_dir, "*.jsonl")))
files = [f for f in files if "trajectory" not in f and "checkpoint" not in f and "sessions.json" not in f]

crons = {}
for f in files:
    for line in open(f):
        line = line.strip()
        if not line: continue
        try:
            obj = json.loads(line)
            if obj.get('type') == 'message':
                msg = obj.get('message', {})
                content = msg.get('content', '')
                if isinstance(content, list):
                    text = ' '.join(c.get('text','') for c in content if isinstance(c,dict) and c.get('type')=='text')
                else:
                    text = str(content)
                # Find cron task definitions
                if '[cron:' in text:
                    match = re.search(r'\[cron:([a-f0-9-]+)\s+([^\]]+)\]', text)
                    if match:
                        cron_id = match.group(1)
                        cron_label = match.group(2)
                        # Extract the full prompt (everything after the cron header)
                        prompt_start = text.find(']', text.find('[cron:')) + 2
                        prompt = text[prompt_start:].strip()
                        if cron_label not in crons:
                            crons[cron_label] = {
                                'id': cron_id,
                                'prompt': prompt[:2000],
                                'file': os.path.basename(f)
                            }
        except:
            pass

for label, info in sorted(crons.items()):
    print(f"\n{'='*60}")
    print(f"📋 {label}")
    print(f"   ID: {info['id']}")
    print(f"   Prompt: {info['prompt'][:1500]}")
